import React, { useEffect } from "react";
import { useNavigate } from "react-router-dom";
import "../App.css";

const Home = () => {
  const navigate = useNavigate();

  useEffect(() => {
    const animateLight = () => {
      const lightElement = document.getElementById("light"); // ✅ ดึง element ใน SVG
      if (lightElement) {
        lightElement.style.fill =
          lightElement.style.fill === "rgb(231, 229, 213)" // #e7e5d5
            ? "#ffe966"
            : "#e7e5d5";
      }
    };

    const interval = setInterval(animateLight, 2000);
    return () => clearInterval(interval);
  }, []);

  return (
    <div className="background-gradient h-screen flex flex-col justify-center items-center text-center relative">
      {/* ✅ ใช้ Inline SVG แทนการใช้ <img> */}
      <svg
        viewBox="0 0 850.39 850.39"
        xmlns="http://www.w3.org/2000/svg"
        className="photoautomat-svg"
      >
        {/* 📌 ส่วนประกอบอื่นๆ ของ SVG */}
        <circle id="light" fill="#e7e5d5" cx="770.17" cy="401.34" r="54.69" />
        {/* เพิ่มองค์ประกอบอื่นๆ ตามที่มีในไฟล์ photoautomat.svg */}
      </svg>

      <button onClick={() => navigate("/welcome")} className="start-button">
        START
      </button>
    </div>
  );
};

export default Home;
